package project

import (
	"fmt"
	"os"
	"path/filepath"
	"strings"
)

// Options holds CLI flags for nurge init.
type Options struct {
	SkipHooks bool
	Force     bool
	Verbose   bool
}

// Step is the interface each init step implements.
type Step interface {
	Name() string
	Done() (bool, error)
	Run() error
}

// Run executes all init steps in order.
func Run(opts Options) error {
	fmt.Println()
	fmt.Println("  nurge — outbound that learns")
	fmt.Println()

	steps := buildSteps(opts)

	for _, s := range steps {
		if !opts.Force {
			done, err := s.Done()
			if err != nil {
				printFail(s.Name(), err)
				return err
			}
			if done {
				printSkip(s.Name())
				continue
			}
		}

		if err := s.Run(); err != nil {
			printFail(s.Name(), err)
			return err
		}
		printDone(s.Name())
	}

	return nil
}

func buildSteps(opts Options) []Step {
	var steps []Step

	steps = append(steps, &projectStep{})
	steps = append(steps, &databaseStep{})
	steps = append(steps, &gitignoreStep{})

	if !opts.SkipHooks {
		steps = append(steps, &hooksStep{})
	}

	steps = append(steps, &skillStep{})
	steps = append(steps, &gitStep{})
	steps = append(steps, &nextStepStep{})

	return steps
}

func printDone(name string) {
	fmt.Fprintf(os.Stdout, "  \033[32m✓\033[0m %s\n", name)
}

func printSkip(name string) {
	fmt.Fprintf(os.Stdout, "  \033[32m✓\033[0m %s (already done)\n", name)
}

func printFail(name string, err error) {
	fmt.Fprintf(os.Stderr, "  \033[31m✗\033[0m %s: %v\n", name, err)
}

// IsDirEmpty returns true if dir contains no entries except allowed ones
// (.nurge, .git, .gitignore, .DS_Store, .claude).
func IsDirEmpty(dir string) (bool, error) {
	allowed := map[string]bool{
		".nurge":     true,
		".git":       true,
		".gitignore": true,
		".DS_Store":  true,
		".claude":    true,
	}

	entries, err := os.ReadDir(dir)
	if err != nil {
		return false, err
	}
	for _, e := range entries {
		name := strings.TrimSuffix(e.Name(), "/")
		if !allowed[name] {
			return false, nil
		}
	}
	return true, nil
}

// IsNurgeProject returns true if dir contains a .nurge/ directory.
func IsNurgeProject(dir string) bool {
	info, err := os.Stat(filepath.Join(dir, ".nurge"))
	return err == nil && info.IsDir()
}

