160→func runSessionStart() error {
161→	// Read stdin (Claude Code sends session info)
162→	input, _ := session.ReadStdin()
163→
164→	// Capture session in DB (graceful — don't fail the hook if DB is missing)
165→	if input != nil && input.SessionID != "" && db.Exists() {
166→		if d, err := db.Open(); err == nil {
167→			db.EnsureSessionTables(d)
168→			session.CreateSession(d, input.SessionID, input.Model, input.Source, input.TranscriptPath)
169→			session.AddEvent(d, input.SessionID, "session_start", input)
170→			d.Close()
171→		}
172→		session.Logger().Info("session-start", "session_id", input.SessionID, "model", input.Model)
173→		session.FlushLog()
174→	}
