	defer d.Close()

	stats, err := email.Stats(d)
	if err == nil {
		s.emailTotal = stats.Total
		s.outboundTotal = stats.ByClass["outbound"]
	}

	weekly, err := email.ThisWeek(d)
	if err == nil {
		s.weeklyStats = weekly
	}

	skills, err := session.ListSkills(d)
	if err == nil {
		s.skillCount = len(skills)
		for _, sk := range skills {
			s.skillNames = append(s.skillNames, sk.SkillName)
		}
	}

	// Contact count (graceful)
	d.QueryRow("SELECT COUNT(*) FROM contacts").Scan(&s.contactCount)

	// Learning count (graceful)
	d.QueryRow("SELECT COUNT(*) FROM learnings").Scan(&s.learningCount)

	return s
}

// hookOutput is the JSON structure Claude Code expects from hook stdout.
type hookOutput struct {
	SystemMessage    string            `json:"systemMessage,omitempty"`
	HookSpecificOut  *hookSpecificOut  `json:"hookSpecificOutput,omitempty"`
}

type hookSpecificOut struct {
	HookEventName     string `json:"hookEventName"`
	AdditionalContext string `json:"additionalContext,omitempty"`
}

// runSessionStart outputs JSON with systemMessage (visible banner) and
// additionalContext (LLM context) for the SessionStart hook.
// Also captures the session in DB + log.
func runSessionStart() error {
	// Read stdin (Claude Code sends session info)
	input, _ := session.ReadStdin()

	// Capture session in DB (graceful — don't fail the hook if DB is missing)
	if input != nil && input.SessionID != "" && db.Exists() {
		if d, err := db.Open(); err == nil {
			db.EnsureSessionTables(d)
			session.CreateSession(d, input.SessionID, input.Model, input.Source, input.TranscriptPath)
			session.AddEvent(d, input.SessionID, "session_start", input)
			d.Close()
		}
		session.Logger().Info("session-start", "session_id", input.SessionID, "model", input.Model)
		session.FlushLog()
	}

	// Sync permissions — ensures existing users get any new permissions
	// added in later versions. Graceful — never fails the hook.
	project.SyncPermissions()

	// Auto-update check (non-blocking, cached)
	updateMsg := checkAndAutoUpdate()

	s := gatherStatus()

	banner := buildBanner(s)
	if updateMsg != "" {
		banner += "\n  " + updateMsg
	}
	context := buildPromptContext(s)

	out := hookOutput{
		SystemMessage: banner,
		HookSpecificOut: &hookSpecificOut{
			HookEventName:     "SessionStart",
			AdditionalContext: context,
		},
	}

	enc := json.NewEncoder(os.Stdout)
	return enc.Encode(out)
}

// runUserPrompt captures a user prompt submission event.
func runUserPrompt() error {
	input, err := session.ReadStdin()
	if err != nil || input == nil || input.SessionID == "" {
		return nil // graceful no-op
	}

	if !db.Exists() {
		return nil
	}
	d, err := db.Open()
	if err != nil {
		return nil
	}
	defer d.Close()

	db.EnsureSessionTables(d)
	session.AddEvent(d, input.SessionID, "prompt", input)

	// Log without prompt content — keep logs lightweight
	session.Logger().Info("prompt", "session_id", input.SessionID)
	session.FlushLog()
	return nil
}

// runStop captures a stop event and creates a checkpoint.
func runStop() error {
	input, err := session.ReadStdin()
	if err != nil || input == nil || input.SessionID == "" {
		return nil
	}

	if !db.Exists() {
		return nil
	}
	d, err := db.Open()
	if err != nil {
		return nil
	}
	defer d.Close()

	db.EnsureSessionTables(d)
	session.AddEvent(d, input.SessionID, "stop", input)
	if len(input.ModifiedFiles) > 0 {
		session.AddCheckpoint(d, input.SessionID, input.ModifiedFiles)
	}

	session.Logger().Info("stop", "session_id", input.SessionID, "reason", input.StopReason)
	session.FlushLog()
	return nil
}

// runSessionEnd marks a session as ended.
func runSessionEnd() error {
	input, err := session.ReadStdin()
	if err != nil || input == nil || input.SessionID == "" {
		return nil
	}

	if !db.Exists() {
		return nil
	}
	d, err := db.Open()
	if err != nil {
		return nil
	}
	defer d.Close()

	db.EnsureSessionTables(d)
	session.EndSession(d, input.SessionID)
	session.AddEvent(d, input.SessionID, "session_end", input)

	session.Logger().Info("session-end", "session_id", input.SessionID)
	session.FlushLog()
	return nil
}

func buildBanner(s *sessionStatus) string {
	var b strings.Builder
	ver := fmt.Sprintf("nurge %s", buildVersion)

	// Line 1: Powered by Nurge
	b.WriteString("\n\nPowered by Nurge\n")
	// Line 2: Version
	fmt.Fprintf(&b, "  %s\n", ver)

	if !s.configLoaded {
		b.WriteString("  Run: nurge to get started")
		return b.String()
	}

	// --- Pre-setup: no connectors yet ---
	hasConnectors := false
	for _, c := range s.connectors {
		if c.Connected {
			hasConnectors = true
			break
		}
	}
	if !hasConnectors {
		b.WriteString("  Run /nurge:setup to connect your email and get started.")
		return b.String()
	}

	// --- Setup in progress ---
	if !s.setupCompleted {
		name := s.settings["user.name"]
		if name != "" {
			fmt.Fprintf(&b, "  Hey %s, setup in progress.\n", name)
		} else {
			b.WriteString("  Setup in progress.\n")
		}
		b.WriteString("  Run /nurge:setup to continue where you left off.")
		return b.String()
	}

	// --- Post-setup: compact rotating dashboard ---
	name := s.settings["user.name"]
	if name != "" {
		fmt.Fprintf(&b, "  Hey %s\n", name)
	}

	// Always show: KPI progress (the one thing that matters most)
	if s.weeklyStats != nil && s.weeklyStats.OutboundSent > 0 {
		fmt.Fprintf(&b, "  This week: %d emails sent", s.weeklyStats.OutboundSent)
		if s.weeklyStats.UniqueContacts > 0 {
			fmt.Fprintf(&b, " → %d contacts", s.weeklyStats.UniqueContacts)
		}
		kpiTarget := s.settings["kpi.daily_emails"]
		if kpiTarget != "" {
			fmt.Fprintf(&b, " (target: %s/day)", kpiTarget)
		}
		b.WriteString("\n")
	} else {
		goal := s.settings["kpi.goal"]
		if goal != "" {
			fmt.Fprintf(&b, "  Goal: %s — no emails sent this week yet\n", goal)
		}
	}

	// Rotate one additional insight based on day-of-year
	// This keeps the banner fresh without overwhelming
	slot := time.Now().YearDay() % 5
	switch slot {
	case 0: // Sending health
		warmup := s.settings["sending.warmup_status"]
		domainType := s.settings["sending.domain_type"]
		if warmup == "fresh" {
			b.WriteString("  Domain is fresh — warmup in progress, conservative limits active\n")
		} else if domainType == "primary" {
			b.WriteString("  Sending from primary domain — consider a dedicated outbound domain\n")
		} else {
			fmt.Fprintf(&b, "  %s emails synced | %d skills active\n", formatCount(s.emailTotal), s.skillCount)
		}
	case 1: // Data snapshot
		fmt.Fprintf(&b, "  Data: %s emails", formatCount(s.emailTotal))
		if s.outboundTotal > 0 {
			fmt.Fprintf(&b, " (%d outbound)", s.outboundTotal)
		}
		if s.contactCount > 0 {
			fmt.Fprintf(&b, " | %d contacts", s.contactCount)
		}
		b.WriteString("\n")
	case 2: // Learnings
		if s.learningCount > 0 {
			fmt.Fprintf(&b, "  %d learnings captured — skills improving with every session\n", s.learningCount)
		} else {
			fmt.Fprintf(&b, "  %d skills active | Start sending to build learnings\n", s.skillCount)
		}
	case 3: // Connected services
		var connList []string
		for id, c := range s.connectors {
			if c.Connected {
				connList = append(connList, capitalize(id))
			}
		}
		fmt.Fprintf(&b, "  Connected: %s | %d skills active\n", strings.Join(connList, ", "), s.skillCount)
	case 4: // Quick action suggestion
		actions := []string{
			"\"research [company]\" — deep-dive a prospect",
			"\"write an email to [persona] at [company]\"",
			"\"/nurge:review\" — check your KPI progress",
			"\"show my pipeline\" — see what needs attention",
		}
		pick := time.Now().YearDay() / 5 % len(actions)
		fmt.Fprintf(&b, "  Try: %s\n", actions[pick])
	}

	return b.String()
}

func buildPromptContext(s *sessionStatus) string {
	var b strings.Builder

	if !s.configLoaded || !s.setupCompleted {
		b.WriteString("You are in a Nurge workspace. Setup is not complete. ")
		b.WriteString("Guide the user to run /nurge:setup to finish configuration. ")
		b.WriteString("Do not attempt to use nurge data commands — they will have no data yet.")
		return b.String()
	}

	// User context
	name := s.settings["user.name"]
	role := s.settings["user.role"]
	if name != "" {
		fmt.Fprintf(&b, "User: %s", name)
		if role != "" {
			fmt.Fprintf(&b, " (%s)", role)
		}
		b.WriteString("\n")
	}

	b.WriteString("You are in a Nurge outbound sales workspace.\n")
	fmt.Fprintf(&b, "Status: Setup complete. %s emails synced (%d outbound). %d contacts. %d skills active.\n",
		formatCount(s.emailTotal), s.outboundTotal, s.contactCount, s.skillCount)

	// KPI context
	goal := s.settings["kpi.goal"]
	dailyTarget := s.settings["kpi.daily_emails"]
	weeklyMeetings := s.settings["kpi.weekly_meetings"]
	if goal != "" {
		fmt.Fprintf(&b, "Outbound goal: %s.", goal)
		if dailyTarget != "" {
			fmt.Fprintf(&b, " Daily target: %s emails.", dailyTarget)
		}
		if weeklyMeetings != "" {
			fmt.Fprintf(&b, " Weekly meeting target: %s.", weeklyMeetings)
		}
		b.WriteString("\n")
	}

	// Sending context
	warmup := s.settings["sending.warmup_status"]
	domainType := s.settings["sending.domain_type"]
	if warmup == "fresh" {
		b.WriteString("IMPORTANT: Domain is fresh/not warmed up. Enforce conservative sending limits. Do not exceed daily target.\n")
	}
	if domainType == "primary" {
		b.WriteString("Note: User is sending from primary business domain. Be conservative with volume.\n")
	}

	// Geography / compliance
	geo := s.settings["prospects.geography"]
	if geo != "" {
		fmt.Fprintf(&b, "Prospect geography: %s.", geo)
		if strings.Contains(strings.ToLower(geo), "eu") || strings.Contains(strings.ToLower(geo), "europe") {
			b.WriteString(" GDPR applies — ensure legitimate interest basis for outreach.")
		}
		b.WriteString("\n")
	}

	// Rules
	b.WriteString("Rules:\n")
	b.WriteString("- Use `nurge` CLI commands for all data access. Never read .nurge/ directly.\n")
	b.WriteString("- For ICP, personas, and product context: nurge config show --format json\n")
	b.WriteString("- For email patterns and insights: nurge context generate --format json\n")
	b.WriteString("- For email stats: nurge emails stats --format json\n")
	b.WriteString("- When sending emails: nurge send (always get user approval first)\n")
	b.WriteString("- When researching prospects: use WebSearch with multiple angles, check company legal pages (mentions légales, impressum), cross-reference before drafting")

	if len(s.skillNames) > 0 {
		fmt.Fprintf(&b, "\nAvailable skills: %s", strings.Join(s.skillNames, ", "))
	}

	return b.String()
}

// --- Auto-update ---

const (
	updateCacheFile = ".nurge/update_check.json"
	updateCheckTTL  = 24 * time.Hour
	githubReleasesURL = "https://api.github.com/repos/usenurge/nurge/releases/latest"
)

type updateCache struct {
	LatestVersion string `json:"latest_version"`
	CheckedAt     string `json:"checked_at"`
	UpdatedAt     string `json:"updated_at,omitempty"`
}

// checkAndAutoUpdate checks for updates (cached, 24h TTL) and auto-updates if needed.
// Returns a message for the banner, or empty string.
func checkAndAutoUpdate() string {
	// Read cache
	cache := readUpdateCache()

	// If checked recently, just report
	if cache != nil && cache.CheckedAt != "" {
		checkedAt, err := time.Parse(time.RFC3339, cache.CheckedAt)
		if err == nil && time.Since(checkedAt) < updateCheckTTL {
			// Cache is fresh — check if we just updated
			if cache.UpdatedAt != "" {
				updatedAt, err := time.Parse(time.RFC3339, cache.UpdatedAt)
				if err == nil && time.Since(updatedAt) < 5*time.Minute {
					// Clear the updated flag for next time
					cache.UpdatedAt = ""
					writeUpdateCache(cache)
					return fmt.Sprintf("Updated to %s", cache.LatestVersion)
				}
			}
			return ""
		}
	}

	// Check for latest version (with timeout)
	latest := fetchLatestVersion()
	if latest == "" {
		// Network failed — update cache timestamp so we don't retry immediately
		if cache == nil {
			cache = &updateCache{}
		}
		cache.CheckedAt = time.Now().UTC().Format(time.RFC3339)
		writeUpdateCache(cache)
		return ""
	}

	// Save to cache
	if cache == nil {
		cache = &updateCache{}
	}
	cache.LatestVersion = latest
	cache.CheckedAt = time.Now().UTC().Format(time.RFC3339)

	// Compare: if current version matches latest, no update needed
	if buildVersion == latest || buildVersion == latest[1:] { // handle v prefix
		writeUpdateCache(cache)
		return ""
	}

	// Different version — auto-update
	if runAutoUpdate() {
		cache.UpdatedAt = time.Now().UTC().Format(time.RFC3339)
		writeUpdateCache(cache)
		return fmt.Sprintf("Updating to %s...", latest)
	}

	writeUpdateCache(cache)
	return ""
}

func readUpdateCache() *updateCache {
	data, err := os.ReadFile(updateCacheFile)
	if err != nil {
		return nil
	}
	var c updateCache
	if err := json.Unmarshal(data, &c); err != nil {
		return nil
	}
	return &c
}

func writeUpdateCache(c *updateCache) {
	data, err := json.Marshal(c)
	if err != nil {
		return
	}
	os.MkdirAll(filepath.Dir(updateCacheFile), 0755)
	os.WriteFile(updateCacheFile, data, 0644)
}

// fetchLatestVersion gets the latest release tag from GitHub. 3s timeout.
func fetchLatestVersion() string {
	client := &http.Client{Timeout: 3 * time.Second}
	resp, err := client.Get(githubReleasesURL)
	if err != nil {
		return ""
	}
	defer resp.Body.Close()

	if resp.StatusCode != 200 {
		return ""
	}

	var release struct {
		TagName string `json:"tag_name"`
	}
	if err := json.NewDecoder(resp.Body).Decode(&release); err != nil {
		return ""
	}
	return release.TagName
}

// runAutoUpdate runs the install script in the background. Returns true if launched.
func runAutoUpdate() bool {
	cmd := exec.Command("sh", "-c", "curl -fsSL https://install.nurge.sh | sh >/dev/null 2>&1")
	if err := cmd.Start(); err != nil {
		return false
	}
	// Don't wait — let it run in background
	go cmd.Wait()
	return true
}

// removeSetupSkill deletes the global setup skill directory after setup is done.
// Graceful — never fails if already removed.
func removeSetupSkill() {
	home, err := os.UserHomeDir()
	if err != nil {
		return
	}
	skillDir := filepath.Join(home, ".claude", "skills", "nurge-setup")
	os.RemoveAll(skillDir) // ignore error — may already be gone
}

func capitalize(s string) string {
	if s == "" {
		return s
	}
	return strings.ToUpper(s[:1]) + s[1:]
}

func formatCount(n int) string {
	if n >= 1000 {
		return fmt.Sprintf("%d,%03d", n/1000, n%1000)
	}
	return fmt.Sprintf("%d", n)
}

package project

import (
	"encoding/json"
	"fmt"
	"os"
	"time"
)

const configFile = ".nurge/config.json"

// ConnectorState holds the state of a single connected service.
type ConnectorState struct {
	Connected   bool   `json:"connected"`
	ConnectedAt string `json:"connected_at,omitempty"`
	Account     string `json:"account,omitempty"`
	Type        string `json:"type"` // "crm" or "email"
}

// Config is the top-level nurge configuration.
type Config struct {
	Version        int                        `json:"version"`
	CreatedAt      string                     `json:"created_at"`
	Connectors     map[string]ConnectorState  `json:"connectors"`
	SetupCompleted bool                       `json:"setup_completed"`
	Settings       map[string]string          `json:"settings,omitempty"`
}

// Path returns the path to config.json.
func Path() string {
	return configFile
}

// Default returns a new Config with default values.
func Default() *Config {
	return &Config{
		Version:        1,
		CreatedAt:      time.Now().UTC().Format(time.RFC3339),
		Connectors:     make(map[string]ConnectorState),
		SetupCompleted: false,
	}
}

// Load reads config from disk.
func Load() (*Config, error) {
	data, err := os.ReadFile(configFile)
	if err != nil {
		return nil, fmt.Errorf("reading config: %w", err)
	}
	var cfg Config
	if err := json.Unmarshal(data, &cfg); err != nil {
		return nil, fmt.Errorf("parsing config: %w", err)
	}
	if cfg.Connectors == nil {
		cfg.Connectors = make(map[string]ConnectorState)
	}
	return &cfg, nil
}

// Write saves config to disk.
func Write(cfg *Config) error {
	data, err := json.MarshalIndent(cfg, "", "  ")
	if err != nil {
		return fmt.Errorf("marshaling config: %w", err)
	}
	if err := os.WriteFile(configFile, data, 0644); err != nil {
		return fmt.Errorf("writing config: %w", err)
	}
	return nil
}

// SetConnector updates a connector in the config and saves.
func SetConnector(id, connType, account string) error {
	cfg, err := Load()
	if err != nil {
		return err
	}
	cfg.Connectors[id] = ConnectorState{
		Connected:   true,
		ConnectedAt: time.Now().UTC().Format(time.RFC3339),
		Account:     account,
		Type:        connType,
	}
	return Write(cfg)
}

// RemoveConnector removes a connector from config and saves.
func RemoveConnector(id string) error {
	cfg, err := Load()
	if err != nil {
		return err
	}
	delete(cfg.Connectors, id)
	return Write(cfg)
}

// Get returns the value for a settings key, or empty string if not set.
func Get(key string) (string, error) {
	cfg, err := Load()
	if err != nil {
		return "", err
	}
	if cfg.Settings == nil {
		return "", nil
	}
	return cfg.Settings[key], nil
}

// Set stores a key/value pair in settings and saves the config.
func Set(key, value string) error {
	cfg, err := Load()
	if err != nil {
		return err
	}
	if cfg.Settings == nil {
		cfg.Settings = make(map[string]string)
	}
	cfg.Settings[key] = value
	return Write(cfg)
}

// SetSetupCompleted sets the top-level setup_completed flag and saves.
func SetSetupCompleted(completed bool) error {
	cfg, err := Load()
	if err != nil {
		return err
	}
	cfg.SetupCompleted = completed
	return Write(cfg)
}

